19	const COMPONENT_PREMIUM = 25;
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const PROCESSING_FEE = 5;
25	const ROUNDING_PRECISION = 6;
26	
27	const componentBasePremium = (count: number): number => {
28	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
29	  return count * COMPONENT_PREMIUM;
30	};
31	
32	const COMPONENT_TYPES = ["rune", "moonstone"];
33	
34	const componentsBasePremium = (items: Item[]): number => {
35	  const counts = new Map<string, number>();
36	  for (const item of items) {
37	    if (COMPONENT_TYPES.includes(item.type)) {
38	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
39	    }
40	  }
41	  let total = 0;
42	  for (const count of counts.values()) {
43	    total += componentBasePremium(count);
44	  }
45	  return total;
46	};
47	
48	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
49	  const results = scenario.steps.map((step) => {
50	    const base = componentsBasePremium(step.items);
51	    const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
52	    const premium = Math.ceil(
53	      Number((withFirstInsurance + PROCESSING_FEE).toFixed(ROUNDING_PRECISION)),
54	    );
55	    return { premium };
56	  });
57	  return { results };
58	};
